import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import api from "../services/api";
import PostItem from "../components/PostItem";
import MapView from "../components/MapView";
import toast from "react-hot-toast";

export default function Dashboard() {

  const [items, setItems] = useState([]);
  const [nearbyItems, setNearbyItems] = useState([]);
  const [search, setSearch] = useState("");
  const [category, setCategory] = useState("");
  const [typeFilter, setTypeFilter] = useState("");
  const [loading, setLoading] = useState(true);

  const user = JSON.parse(localStorage.getItem("user") || "null");
  const userId = user?._id || null;

  const loadItems = async () => {

    try {

      setLoading(true);

      const query = new URLSearchParams();

      if (search) query.append("search", search);
      if (category) query.append("category", category);

      const res = await api.get(`/items?${query.toString()}`);

      setItems(res.data);

    } catch {

      toast.error("Failed to load items");

    } finally {

      setLoading(false);

    }

  };

  useEffect(() => {
    loadItems();
  }, [search, category]);

  const findNearbyItems = () => {

    if (!navigator.geolocation) {
      toast.error("Geolocation not supported");
      return;
    }

    navigator.geolocation.getCurrentPosition(async (position) => {

      const lat = position.coords.latitude;
      const lng = position.coords.longitude;

      try {

        const res = await api.get(`/items/nearby?lat=${lat}&lng=${lng}`);

        setNearbyItems(res.data);

        toast.success("Nearby items loaded");

      } catch {

        toast.error("Failed to load nearby items");

      }

    });

  };

  const filteredItems = typeFilter
    ? items.filter((i) => i.type === typeFilter)
    : items;

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith("http")) return path;
    return `http://localhost:5000${path.startsWith("/") ? "" : "/"}${path}`;
  };

  if (loading) {

    return (
      <div className="p-8 text-center text-lg">
        Loading dashboard...
      </div>
    );

  }

  return (

    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-blue-50 p-6">

      <div className="bg-white rounded-xl shadow p-6 mb-8">

        <h1 className="text-3xl font-extrabold">
          weFOUNDit
        </h1>

        <p className="text-gray-600 mt-2">
          Community powered Lost & Found system
        </p>

      </div>

      {/* SEARCH + FILTERS */}

      <div className="bg-white p-4 rounded-xl shadow mb-8 flex flex-wrap gap-3">

        <input
          type="text"
          placeholder="Search items..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="border p-2 rounded w-60"
        />

        <select
          value={category}
          onChange={(e) => setCategory(e.target.value)}
          className="border p-2 rounded"
        >
          <option value="">All Categories</option>
          <option value="electronics">Electronics</option>
          <option value="wallet">Wallet</option>
          <option value="documents">Documents</option>
          <option value="keys">Keys</option>
          <option value="bags">Bags</option>
          <option value="clothing">Clothing</option>
          <option value="pets">Pets</option>
          <option value="jewelry">Jewelry</option>
          <option value="other">Other</option>
        </select>

        <select
          value={typeFilter}
          onChange={(e) => setTypeFilter(e.target.value)}
          className="border p-2 rounded"
        >
          <option value="">All</option>
          <option value="lost">Lost</option>
          <option value="found">Found</option>
        </select>

        <button
          onClick={findNearbyItems}
          className="bg-purple-600 text-white px-4 py-2 rounded"
        >
          Nearby Items
        </button>

      </div>

      {/* MAP */}

      <div className="bg-white rounded-xl shadow p-6 mb-10">

        <h2 className="text-2xl font-bold mb-4">
          Lost & Found Map
        </h2>

        <MapView items={items} />

      </div>

      <div className="mb-8">
        <PostItem onPosted={loadItems} />
      </div>

      {/* ITEMS */}

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

        {filteredItems.map((item) => {

          const isOwner =
            userId &&
            (typeof item.user === "string"
              ? item.user
              : item.user?._id) === userId;

          const imageUrl =
            item.images?.length > 0
              ? getImageUrl(item.images[0])
              : null;

          return (

            <div key={item._id} className="bg-white rounded-xl shadow p-4">

              {imageUrl && (

                <img
                  src={imageUrl}
                  alt={item.title}
                  className="h-40 w-full object-cover rounded-lg mb-3"
                />

              )}

              <h2 className="text-lg font-bold mb-1">
                {item.title}
              </h2>

              <p className="text-sm text-gray-500 capitalize mb-1">
                {item.category}
              </p>

              <p className="text-sm text-gray-600">
                {item.description}
              </p>

              <Link
                to={`/items/${item._id}`}
                className="block mt-3 text-center bg-blue-600 text-white py-2 rounded"
              >
                View Details
              </Link>

            </div>

          );

        })}

      </div>

    </div>

  );

}
